const input = $input.first().json;
const q = input.query || {};
return [{ json: {
  limit: q.limit || '20',
  page: q.page || '1',
  search: q.search || '',
  category: q.category || '',
  sort: q.sort || 'regdt'
} }];

const raw = $input.first().json;
let data = raw;
if (typeof raw.data === 'string') { try { data = JSON.parse(raw.data); } catch(e) {} }
let products = [];
if (data.list && Array.isArray(data.list)) {
  products = data.list;
} else if (data && typeof data === 'object') {
  products = Object.values(data).filter(v => typeof v === 'object' && v !== null && v.uid);
}

const items = products.map(p => {
  const sell = parseInt(p.sellprice || '0');
  const consumer = parseInt(p.consumerprice || '0');
  const discount = consumer > 0 && consumer > sell ? Math.round((1 - sell / consumer) * 100) : 0;
  const img = p.maximage || '';
  return {
    id: String(p.uid || ''),
    name: p.product_name || '',
    price: consumer > 0 ? consumer : sell,
    salePrice: sell,
    discount,
    imageUrl: img.startsWith('http') ? img : img ? 'https://foreverlove.co.kr' + img : '',
    thumbnailUrl: (p.minimage || '').startsWith('http') ? p.minimage : p.minimage ? 'https://foreverlove.co.kr' + p.minimage : '',
    category: p.category_name || '',
    brand: p.brname || '',
    isSoldOut: p.display !== 'Y' || parseInt(p.quantity || '999') === 0,
    isNew: p.np_condition === 'new',
    isBest: p.best_product_display === 'Y',
    regdate: p.regdate || '',
  };
}).filter(p => p.id && p.name);

return [{ json: {
  success: true,
  data: items,
  total: parseInt(data.totalCount || '0'),
  totalPage: parseInt(data.totalPage || '0'),
  page: parseInt(data.page || '1')
} }];

const input = $input.first().json;
const q = input.query || {};
return [{ json: { id: q.id || '' } }];

const raw = $input.first().json;
let data = raw;
if (typeof raw.data === 'string') { try { data = JSON.parse(raw.data); } catch(e) {} }
let products = data.list || [];
if (!Array.isArray(products)) {
  products = Object.values(data).filter(v => typeof v === 'object' && v !== null && v.uid);
}
const p = products[0] || {};
if (!p.uid) return [{ json: { success: false, error: '상품을 찾을 수 없습니다' } }];

const sell = parseInt(p.sellprice || '0');
const consumer = parseInt(p.consumerprice || '0');
const discount = consumer > 0 && consumer > sell ? Math.round((1 - sell / consumer) * 100) : 0;
const makeUrl = (img) => {
  if (!img) return '';
  return img.startsWith('http') ? img : 'https://foreverlove.co.kr' + img;
};

const detail = {
  id: String(p.uid),
  name: p.product_name || '',
  price: consumer > 0 ? consumer : sell,
  salePrice: sell,
  discount,
  imageUrl: makeUrl(p.maximage),
  images: [p.maximage, p.minimage, p.tinyimage].filter(Boolean).map(makeUrl),
  description: p.product_content ? Buffer.from(p.product_content, 'base64').toString('utf-8') : '',
  category: p.category_name || '',
  brand: p.brname || '',
  isSoldOut: p.display !== 'Y' || parseInt(p.quantity || '999') === 0,
  options: [],
  quantity: parseInt(p.quantity || '0'),
};

if (p.options && p.options.option) {
  const opts = Array.isArray(p.options.option) ? p.options.option : [p.options.option];
  detail.options = opts.map(o => ({ name: o.option_name || '', values: (o.option_value || '').split('|').map(v => v.trim()).filter(Boolean) }));
}

return [{ json: { success: true, data: detail } }];

const raw = $input.first().json;
let data = raw;
if (typeof raw.data === 'string') { try { data = JSON.parse(raw.data); } catch(e) {} }
let categories = [];
if (data.list && Array.isArray(data.list)) {
  categories = data.list;
} else if (data && typeof data === 'object') {
  categories = Object.values(data).filter(v => typeof v === 'object' && v !== null);
}
const items = categories.map(c => ({
  id: c.cate_no || c.id || '',
  name: c.cate_name || c.name || '',
  parentId: c.parent_cate_no || '',
  depth: parseInt(c.depth || '1'),
})).filter(c => c.id && c.name);
return [{ json: { success: true, data: items } }];
